import React from "react";
import styleLearningLink from "./Learning_link.module.css";

const Learning_link = () => {
  return (
    <div className={styleLearningLink.container}>
      <ul>
        <li className={styleLearningLink.link}>
          <a href="#3">Adobe Photoshop</a>
        </li>
        <li>
          <a href="#3">Adobe Illustrator</a>
        </li>
        <li>
          <a href="#3">Figma</a>
        </li>
      </ul>
    </div>
  );
};

export default Learning_link;
